 20	  EnrollDiscoveredApplicationAction,
 21	  EnrollDiscoveredApplicationStateType,
 22	} from '../../utils/reducer';
 23	import './configuration-step.scss';
 24	import { RecipeParameterInput } from './recipe-parameter-input';
 25	
 26	const getRecipeOptions = (
 27	  searchResultItem: SearchResultItemType[]
 28	): JSX.Element[] =>
 29	  searchResultItem?.map((item) => {
 30	    // Display each recipe name from selected cluster and namespaces as option
 31	    const { name, namespace } = item;
 32	    const recipeNamespaceName = getNameNamespace(name, namespace);
 33	    return (
 34	      <SelectOption
 35	        id={recipeNamespaceName}
 36	        key={recipeNamespaceName}
 37	        data-test="cluster-dropdown-item"
 38	        value={recipeNamespaceName}
 39	        description={namespace}
 40	      >
 41	        {name}
 42	      </SelectOption>
 43	    );
 44	  });
 45	
 46	export const RecipeSelection: React.FC<RecipeSelectionProps> = ({
 47	  recipeName,
 48	  clusterName,
 49	  recipeNamespace,
 50	  namespaces,
 51	  isValidationEnabled,
 52	  dispatch,
 53	}) => {
 54	  const { t } = useCustomTranslation();
 55	
 56	  const searchQuery = React.useMemo(
 57	    () => queryRecipesFromCluster(clusterName, namespaces.map(getName)),
 58	    [clusterName, namespaces]
 59	  );
 60	
 61	  // ACM search proxy API call
 62	  const [searchResult, searchError, searchLoaded] =
 63	    useACMSafeFetch(searchQuery);
 64	
 65	  const recipeOptions =
 66	    searchLoaded && !searchError
 67	      ? getRecipeOptions(searchResult?.data.searchResult?.[0]?.items || [])
 68	      : [];
 69	
 70	  // Multiple namespace can have recipe with same name,
 71	  // Converting into name/namespace for unique identification in dropdown option
 72	  const recipeNameNamespace = getNameNamespace(recipeName, recipeNamespace);
 73	  // For no recipe found has different validation message
 74	  // For recipe not selected has different validation message
 75	  const recipeValidated = getValidatedProp(
 76	    (isValidationEnabled && !recipeNamespace) || !recipeOptions.length
 77	  );
 78	
 79	  const setRecipeNameNamespace = (nameNamespace: string) =>
 80	    dispatch({
 81	      type: EnrollDiscoveredApplicationStateType.SET_RECIPE_NAME_NAMESPACE,
 82	      payload: nameNamespace,
 83	    });
 84	
 85	  return (
 86	    <>
 87	      {/* todo(bipuladh): Add form validation again */}
 88	      {searchLoaded && !searchError ? (
 89	        <FormGroup
 90	          label={t('Recipe list')}
 91	          fieldId="recipe-selection"
 92	          isRequired
 93	        >
 94	          <Text>
 95	            {t(
 96	              'Only recipes of the selected namespaces will appear in the list.'
 97	            )}
 98	          </Text>
 99	          <SingleSelectDropdown
100	            className="pf-v6-u-w-50 pf-v6-u-mt-sm"
101	            id="recipe-selection-dropdown"
102	            placeholderText={t('Select a recipe')}
103	            selectedKey={recipeNameNamespace}
104	            selectOptions={recipeOptions}
105	            onChange={setRecipeNameNamespace}
106	            required
107	            validated={recipeValidated}
108	            isDisabled={!recipeOptions.length}
109	          />
110	          <FormHelperText>
111	            <HelperText>
112	              <HelperTextItem variant={recipeValidated}>
113	                {!recipeOptions.length ? t('No recipe found') : t('Required')}
114	              </HelperTextItem>
115	            </HelperText>
116	          </FormHelperText>
117	        </FormGroup>
118	      ) : (
119	        <StatusBox loaded={searchLoaded} loadError={searchError} />
120	      )}
121	
122	      {recipeNameNamespace && <RecipeParameterInput dispatch={dispatch} />}
123	    </>
124	  );
125	};
126	
127	type RecipeSelectionProps = {
128	  // Selected recipe name
129	  recipeName: string;
130	  // Selected recipe namespace
131	  recipeNamespace: string;
132	  // Selected discovered application deployment cluster
133	  clusterName: string;
134	  // Selected discovered application namespaces
135	  namespaces: K8sResourceCommon[];
136	  // Form validation is enabled/disabled
137	  isValidationEnabled: boolean;
138	  // Update state
139	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>;
140	};

